function q(id, section, topic, difficulty, text, correct, wrongOptions, explanation) {
  const optionCount = wrongOptions.length + 1;
  const answer = answerIndex(id, optionCount);
  const options = wrongOptions.slice();
  options.splice(answer, 0, correct);

  return {
    id,
    section,
    topic,
    difficulty,
    text,
    options,
    answer,
    explanation,
    reference: referenceFor(section)
  };
}

function answerIndex(id, optionCount) {
  if (optionCount === 3) return (id * 11 + Math.floor(id / 6)) % 3;
  return (id * 5 + Math.floor(id / 4)) % 4;
}

function referenceFor(section) {
  if (section === "Anexo A") return "Programa AENA IIIJ05 2026 - Anexo A";
  if (section === "Anexo B") return "Programa AENA IIIJ05 2026 - Anexo B";
  if (section === "Supuesto teórico-práctico") return "Programa AENA IIIJ05 2026 - Supuesto teórico-práctico";
  if (section === "Inglés técnico") return "Programa AENA IIIJ05 2026 - Inglés técnico";
  return "Programa AENA IIIJ05 2026 - Inglés escrito general";
}